func TestAccTagBinguet_createAndReadBack(t *testing.T) {
	testAccPreCheck(t)
	resourceName := "matomo_tagmanager_tag_binguet.test"

	resource.Test(t, resource.TestCase{
		ProtoV6ProviderFactories: testAccProtoV6ProviderFactories,
		Steps: []resource.TestStep{
			{
				Config: testAccTagBinguetConfig(),
				Check: resource.ComposeAggregateTestCheckFunc(
					resource.TestCheckResourceAttrSet(resourceName, "id"),
				),
			},
			{
				ResourceName:      resourceName,
				ImportState:       true,
				ImportStateVerify: true,
			},
		},
	})
}

func testAccTagBinguetConfig() string {
	return `
provider "matomo" {}

resource "matomo_site" "test" {
  name = "Generated BingUET Acceptance Site"
  urls = ["https://acc-generated-binguet.example.com"]
}

resource "matomo_tagmanager_container" "test" {
  site_id = matomo_site.test.id
  context = "web"
  name    = "Generated BingUET Acceptance Container"
}

resource "matomo_tagmanager_trigger" "test" {
  container_id = matomo_tagmanager_container.test.id
  type         = "PageView"
  name         = "Generated BingUET Acceptance Trigger"
}

resource "matomo_tagmanager_tag_binguet" "test" {
  container_id = matomo_tagmanager_container.test.id
  name         = "generated-test-binguet"
  fire_trigger_ids = [matomo_tagmanager_trigger.test.id]
  // BingUETTag.php's validate closure runs the value through NumberRange(),
  // rejecting anything non-numeric ("The value is not a number.") -
  // confirmed by reading the source directly.
  bing_ad_id = "1234567890"
}
`
}
